1	export interface Item {
2	  type: string;
3	}
4	
5	export interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	export interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	export interface ScenarioResult {
16	  results: { premium: number }[];
17	}
18	
19	const PROCESSING_FEE = 5;
20	
21	const BASE_PRICE_BY_TYPE: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	};
26	
27	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
28	
29	const quotePremium = (step: QuoteStep): number =>
30	  step.items.reduce((sum, item) => sum + basePriceFor(item), 0) + PROCESSING_FEE;
31	
32	export const runScenario = (scenario: Scenario): ScenarioResult => ({
33	  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
34	});
