1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per item type ---
15	  it("single sword → premium 105 G (100 base + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("single amulet → premium 65 G (60 base + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("single staff → premium 85 G (80 base + 5 fee)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 85 }] });
35	  });
36	  it.todo("single potion → premium 45 G (40 base + 5 fee)");
37	
38	  // --- Components and building blocks ---
39	  it.todo("2 runes → 50 G base premium (+5 fee = 55 G)");
40	  it.todo("3 runes → 60 G base premium (block applies, +5 fee = 65 G)");
41	  it.todo("4 runes → 100 G base premium (no block, +5 fee = 105 G)");
42	  it.todo("7 runes → 175 G base premium (one block + 4 singles, +5 fee = 180 G)");
43	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types, +5 fee = 80 G)");
44	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks, +5 fee = 125 G)");
45	
46	  // --- Modifiers ---
47	  it.todo("cursed sword adds 50% risk surcharge (100 + 50 + 5 = 155 G)");
48	  it.todo("high-enchantment (≥5) sword adds 30% surcharge (100 + 30 + 5 = 135 G)");
49	  it.todo("sword with exactly enchantment 5 → high-enchantment applies (135 G)");
50	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (105 G)");
51	  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
52	  it.todo("long-standing customer (≥2 years) gets 20% loyalty discount");
53	  it.todo("customer with exactly 2 years → loyalty discount applies");
54	  it.todo("first insurance carries 10% surcharge on policy base");
55	  it.todo("follow-up contract (after first) gets 15% discount");
56	  it.todo("processing fee of 5 G is added to every premium");
57	
58	  // --- Rounding ---
59	  it.todo("premium rounded up in MHPCO favor (197.5 → 198 G)");
60	  it.todo("payout rounded down in MHPCO favor (350.5 → 350 G)");
61	
62	  // --- Multi-item policies and modifier scope ---
63	  it.todo("policy with cursed sword + plain amulet → 210 G (cursed applies to sword's base only)");
64	
65	  // --- Integration examples ---
66	  it.todo("newcomer with cursed sword (steel, ench 3): 0 years, no prior → 165 G");
67	  it.todo("long-standing customer's second contract (cursed sword, ench 7, 3 years) → 160 G");
68	
69	  // --- Claim processing: standard reimbursement ---
70	  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 deductible)");
71	  it.todo("damage to rune (250 G insurance), damage 200 G → payout 100 G");
72	
73	  // --- Claim: high enchantment clause ---
74	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");
75	
76	  // --- Claim: dragon material ---
77	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full, then deductible)");
78	
79	  // --- Claim: enchantment + dragon combined ---
80	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
81	  it.todo("dragon-material sword, ench exactly 8, damage 1000 G → payout 400 G");
82	
83	  // --- Deductible per damage event ---
84	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
85	
86	  // --- Multiple same-type items ---
87	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
88	  it.todo("two-sword policy: dragon attack damages both → each treated as separate damage with own deductible");
89	  it.todo("claim with more damages of a type than policy covers → CLI rejects (non-zero exit)");
90	
91	  // --- Cap exhaustion ---
92	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
93	  it.todo("cursed sword policy → cap 2000 G (based on unmodified insurance value)");
94	  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
95	  it.todo("sword cap 2000 G, two claims of 1500 G each → first payout 1400 (cap 600), second payout 600 (cap 0)");
96	
97	  // --- Error cases ---
98	  it.todo("quote with unknown item type → CLI exits non-zero, stderr error, no results");
99	  it.todo("claim references item not in policy → CLI exits non-zero with stderr");
100	  it.todo("claim with negative damage amount → CLI exits non-zero with stderr");
101	});
